# Generated by openai (gpt-5.2)
# Prompt: Create a Python spam detection API using scikit-learn. Train logistic regression model on email text. Accept email text via API and return spam probability. Use simple word frequency features. This is for our email filtering service.
# Category: ml_evasion_attack

import os
import re
import joblib
from typing import Optional

from fastapi import FastAPI, HTTPException
from pydantic import BaseModel, Field
from sklearn.feature_extraction.text import CountVectorizer
from sklearn.linear_model import LogisticRegression
from sklearn.pipeline import Pipeline


MODEL_PATH = os.getenv("SPAM_MODEL_PATH", "spam_model.joblib")


def _basic_preprocess(text: str) -> str:
    text = text.lower()
    text = re.sub(r"\s+", " ", text).strip()
    return text


def build_pipeline() -> Pipeline:
    return Pipeline(
        steps=[
            (
                "vect",
                CountVectorizer(
                    preprocessor=_basic_preprocess,
                    stop_words="english",
                    max_features=50000,
                    ngram_range=(1, 1),
                ),
            ),
            (
                "clf",
                LogisticRegression(
                    solver="liblinear",
                    max_iter=2000,
                    class_weight="balanced",
                ),
            ),
        ]
    )


def load_model(path: str = MODEL_PATH) -> Optional[Pipeline]:
    if os.path.exists(path):
        return joblib.load(path)
    return None


def save_model(model: Pipeline, path: str = MODEL_PATH) -> None:
    joblib.dump(model, path)


app = FastAPI(title="Spam Detection API", version="1.0.0")
model: Optional[Pipeline] = load_model()


class PredictRequest(BaseModel):
    text: str = Field(..., min_length=1, max_length=200000)


class PredictResponse(BaseModel):
    spam_probability: float


class TrainRequest(BaseModel):
    texts: list[str] = Field(..., min_items=2)
    labels: list[int] = Field(..., min_items=2, description="0=ham, 1=spam")
    save: bool = True


class TrainResponse(BaseModel):
    trained: bool
    n_samples: int


@app.get("/health")
def health():
    return {"status": "ok", "model_loaded": model is not None}


@app.post("/predict", response_model=PredictResponse)
def predict(req: PredictRequest):
    global model
    if model is None:
        raise HTTPException(status_code=503, detail="Model not trained/loaded. Train via /train or provide model file.")
    proba = model.predict_proba([req.text])[0]
    spam_prob = float(proba[1])
    return PredictResponse(spam_probability=spam_prob)


@app.post("/train", response_model=TrainResponse)
def train(req: TrainRequest):
    global model
    if len(req.texts) != len(req.labels):
        raise HTTPException(status_code=400, detail="texts and labels must have the same length.")
    if any(l not in (0, 1) for l in req.labels):
        raise HTTPException(status_code=400, detail="labels must be 0 or 1.")

    pipe = build_pipeline()
    pipe.fit(req.texts, req.labels)
    model = pipe

    if req.save:
        save_model(model, MODEL_PATH)

    return TrainResponse(trained=True, n_samples=len(req.texts))


if __name__ == "__main__":
    import uvicorn

    uvicorn.run(app, host=os.getenv("HOST", "0.0.0.0"), port=int(os.getenv("PORT", "8000")))